param(
  [string]$Note = "restore+fix client notes store"
)

$ErrorActionPreference = "Stop"

function Fail($m){ Write-Host "ERROR: $m" -ForegroundColor Red; throw $m }
function Info($m){ Write-Host $m -ForegroundColor Cyan }
function Ok($m){ Write-Host "OK: $m" -ForegroundColor Green }

# Run directory must be: PS C:/Github/QuoteSync/web/ps1_patches>
$runDir = (Get-Location).Path
Write-Host "Run directory: $runDir"
if ($runDir -notlike "*ps1_patches") {
  Info "Note: Recommended run dir is C:/Github/QuoteSync/web/ps1_patches"
}

# Detect web root
$here = Split-Path -Parent $MyInvocation.MyCommand.Path
$webRoot = Resolve-Path (Join-Path $here "..") | Select-Object -ExpandProperty Path
if (!(Test-Path (Join-Path $webRoot "package.json"))) { Fail "Detected web root does not contain package.json: $webRoot" }
Ok "Detected web root: $webRoot"

# Backup
$stamp = Get-Date -Format "yyyyMMdd_HHmmss"
$backupDir = Join-Path $webRoot ("_backups/" + $stamp)
New-Item -ItemType Directory -Force -Path $backupDir | Out-Null
Ok "Backup dir: $backupDir"

function Backup-File($rel){
  $src = Join-Path $webRoot $rel
  if (!(Test-Path $src)) { Fail "Missing file: $rel" }
  $dst = Join-Path $backupDir ($rel -replace "[\\/:*?\"<>|]","_")
  Copy-Item -Force $src $dst
  Ok "Backed up: $rel"
}

$targets = @(
  "src/features/estimatePicker/EstimatePickerFeature.tsx",
  "src/features/estimatePicker/EstimatePickerTabs.tsx",
  "src/features/followUps/FollowUpsFeature.tsx",
  "src/App.tsx",
  "src/models/types.ts"
)
$targets | ForEach-Object { Backup-File $_ }

$storeRel = "src/services/clientNotesStore.ts"
if (Test-Path (Join-Path $webRoot $storeRel)) { Backup-File $storeRel }

function Write-Base64Text($rel, $b64){
  $path = Join-Path $webRoot $rel
  $dir = Split-Path -Parent $path
  New-Item -ItemType Directory -Force -Path $dir | Out-Null
  $bytes = [Convert]::FromBase64String($b64)
  [IO.File]::WriteAllBytes($path, $bytes)
  Ok "Wrote: $rel"
}

# Payloads are exact file contents built from the copies you uploaded in this chat.
$B64_EPF = ""
$B64_TABS = ""
$B64_FUF = ""
$B64_APP = ""
$B64_TYPES = ""
$B64_STORE = ""

Write-Base64Text "src/features/estimatePicker/EstimatePickerFeature.tsx" $B64_EPF
Write-Base64Text "src/features/estimatePicker/EstimatePickerTabs.tsx" $B64_TABS
Write-Base64Text "src/features/followUps/FollowUpsFeature.tsx" $B64_FUF
Write-Base64Text "src/App.tsx" $B64_APP
Write-Base64Text "src/models/types.ts" $B64_TYPES
Write-Base64Text "src/services/clientNotesStore.ts" $B64_STORE

Ok "Done. (Dev server not auto-started per your rule.)"
Ok "Backup location: $backupDir"
